#include "kernel_operator.h" class KernelTanh {
public:
__aicore__ inline KernelTanh() {} __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
uint32_t totalLength,
uint32_t tileLength, uint32_t blockDim)
this->totalLength = totalLength;
this->tileLength = tileLength;
this->blockDim = blockDim; const uint32_t bid = AscendC::GetBlockIdx();
const uint32_t base = (totalLength / blockDim);
const uint32_t rem = totalLength - base * blockDim;
const uint32_t myLen = base + (bid < rem ? 1u : 0u);
const uint32_t myOff = bid * base + (bid < rem ? bid : rem); startOffset = myOff;
localLength = myLen; xGm.SetGlobalBuffer((__gm__ float*)x + startOffset, localLength);
yGm.SetGlobalBuffer((__gm__ float*)y + startOffset, localLength); constexpr uint32_t PAD_BYTES = 256; pipe.InitBuffer(inQueueX, 2, tileLength * sizeof(float)
+ PAD_BYTES);
pipe.InitBuffer(outQueueY, 2, tileLength * sizeof(float)
+ PAD_BYTES);

// Tanh tmp UB, aligned to 256B. Keep conservative sizing.
const uint32_t tmpBytes = ((tileLength * 8u + 255u) / 256u)
* 256u;
pipe.InitBuffer(tmpQueue, 1, tmpBytes); __aicore__ inline void Process()
if (localLength == 0) return; uint32_t cur = (localLength > tileLength) ?
tileLength : localLength;
CopyIn(offset, cur);
offset += cur; while (offset < localLength) {
const uint32_t next = (offset + tileLength <= localLength) ?
tileLength : (localLength - offset); CopyIn(offset, next);
Compute(cur);
CopyOut(offset - cur, cur); cur = next;
offset += next; Compute(cur);
CopyOut(localLength - cur, cur); private:
__aicore__ inline void CopyIn(uint32_t offset, uint32_t len)
AscendC::LocalTensor<float> xLocal =
inQueueX.AllocTensor<float>();
AscendC::DataCopy(xLocal, xGm[offset], len);
inQueueX.EnQue(xLocal); __aicore__ inline void Compute(uint32_t len)
AscendC::LocalTensor<float> xLocal = inQueueX.DeQue<float>();
AscendC::LocalTensor<float> yLocal =
outQueueY.AllocTensor<float>(); AscendC::LocalTensor<uint8_t> tmp =
tmpQueue.AllocTensor<uint8_t>();
AscendC::Tanh<float>(yLocal, xLocal, tmp, len);
tmpQueue.FreeTensor(tmp); outQueueY.EnQue<float>(yLocal);
inQueueX.FreeTensor(xLocal); __aicore__ inline void CopyOut(uint32_t offset, uint32_t len)
AscendC::LocalTensor<float> yLocal = outQueueY.DeQue<float>();
AscendC::DataCopy(yGm[offset], yLocal, len);
outQueueY.FreeTensor(yLocal); private:
AscendC::TPipe pipe;
AscendC::TQue<AscendC::TPosition::VECIN, 2> inQueueX;
AscendC::TQue<AscendC::TPosition::VECOUT, 2> outQueueY;
AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue; AscendC::GlobalTensor<float> xGm;
AscendC::GlobalTensor<float> yGm;

uint32_t totalLength = 0;
uint32_t tileLength = 0;
uint32_t blockDim = 1; uint32_t startOffset = 0;
uint32_t localLength = 0; extern "C" __global__ __aicore__ void tanh_custom(GM_ADDR x,
GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
GET_TILING_DATA(tiling_data, tiling);
KernelTanh op;
op.Init(x, y, tiling_data.totalLength,
tiling_data.tileLength, tiling_data.blockDim);
op.Process();
